sdk_integration.usage:
import { ControlRoomSession } from '@control-room/sdk';

// Initialize the SDK (once, on app load)
const session = new ControlRoomSession({
  tenant_id: 'e63d3b80-3289-499e-84ca-292b70c13ac6',
  supabaseUrl: 'YOUR_SUPABASE_URL',
  supabaseKey: 'YOUR_SUPABASE_PUBLISHABLE_KEY',
});

// When user enters their reference number:
const state = await session.connect(userEnteredReference);
// state.component_key → which React component to render
// state.current_state → the state machine key

// Listen for operator actions (real-time)
session.subscribe((newState) => {
  // Operator clicked 'Approve' or 'Next' → screen changes instantly
  renderComponent(newState.component_key);
});

// Send user input to the operator's dashboard
await session.sendInput({ field_name: 'value' });
